noncompliant:
// Noncompliant: using 'is' with 'this' is redundant
public class Food
{
    public void DoSomething()
    {
        if (this is Pizza) // Noncompliant - this is always a Food or derived type
        {
            // ...
        }
    }
}

compliant:
// Compliant: check type without 'this'
public class Food
{
    public void DoSomething()
    {
        if (GetType() == typeof(Pizza))
        {
            // ...
        }
    }
}

// Compliant: use pattern matching on parameters, not 'this'
public void Process(Food food)
{
    if (food is Pizza pizza) // OK - checking parameter
    {
        // Use pizza
    }
}
